sys_script_include.script:
var AROPCheckSeeder_TPRM = Class.create();
AROPCheckSeeder_TPRM.prototype = {
    initialize: function() {},
    getChecks: function() {
        return [{"module":"TPRM","check_name":"Now Assist for TPRM Installed","order":null,"check_script":"(function(){
var sa=new GlideRecord("sys_store_app");
sa.addQuery("scope","sn_tprm_genai");
sa.setLimit(1);sa.query();
if(sa.next())return{status:"ready",actualValue:"v"+sa.getValue("version"),finding:"Now Assist for TPRM is installed."};
return{status:"value_blocker",actualValue:"Not installed",finding:"Now Assist for TPRM (sn_tprm_gen_ai) is not installed."};
})()","ai_justification":"Now Assist for TPRM enables AI-powered assessment summarization, vendor risk analysis, and issue generation recommendations. Without this plugin, risk teams cannot leverage generative AI to accelerate third-party assessments and reduce manual review effort.","remediation_guidance":"Install Now Assist for TPRM from the ServiceNow Store.","is_manual":"0","is_clone_sensitive":"0"},{"module":"TPRM","check_name":"Risk Intelligence Scores Active","order":null,"check_script":"(function(){
var ga=new GlideAggregate("sn_vdr_risk_asmt_security_score");
ga.addAggregate("COUNT");ga.query();
var c=ga.next()?parseInt(ga.getAggregate("COUNT")):0;
if(c>=10)return{status:"ready",actualValue:c+" scores",finding:c+" risk intelligence scores found."};
if(c>0)return{status:"needs_attention",actualValue:c+" scores",finding:c+" scores found."};
return{status:"needs_attention",actualValue:"0 scores",finding:"No risk intelligence scores found. Consider integrating a risk intelligence provider."};
})()","ai_justification":"Active Risk Intelligence scores provide the AI-generated vendor risk signals that Now Assist uses to prioritize assessments and surface high-risk third parties. Without active scoring, AI-powered risk prioritization and early warning capabilities are unavailable.","remediation_guidance":"Configure a risk intelligence provider to feed external risk scores into TPRM.","is_manual":"0","is_clone_sensitive":"0"},{"module":"TPRM","check_name":"Risk Issues with Descriptions Volume","order":null,"check_script":"(function(){
var ga=new GlideAggregate("sn_vdr_risk_asmt_issue");
ga.addQuery("description","!=","");
ga.addAggregate("COUNT");ga.query();
var c=ga.next()?parseInt(ga.getAggregate("COUNT")):0;
var ga2=new GlideAggregate("sn_vdr_risk_asmt_issue");
ga2.addAggregate("COUNT");ga2.query();
var total=ga2.next()?parseInt(ga2.getAggregate("COUNT")):0;
if(c>=20)return{status:"ready",actualValue:c+"/"+total+" with descriptions",finding:c+" risk issues have descriptions."};
if(c>0)return{status:"needs_attention",actualValue:c+"/"+total+" with descriptions",finding:c+" of "+total+" issues have descriptions."};
return{status:"value_blocker",actualValue:"0 with descriptions",finding:"No risk issues with descriptions found."};
})()","ai_justification":"Risk issues with detailed descriptions provide the content that Now Assist uses to generate summaries and recommendations. Well-documented risk issues enable AI to produce more accurate assessments and improve the quality of automated issue generation.","remediation_guidance":"Ensure risk issues are created with detailed descriptions.","is_manual":"0","is_clone_sensitive":"0"},{"module":"TPRM","check_name":"Risk Task Volume","order":null,"check_script":"(function(){
var ga=new GlideAggregate("sn_vdr_risk_asmt_task");
ga.addAggregate("COUNT");ga.query();
var c=ga.next()?parseInt(ga.getAggregate("COUNT")):0;
if(c>=20)return{status:"ready",actualValue:c+" tasks",finding:c+" risk tasks found."};
if(c>0)return{status:"needs_attention",actualValue:c+" tasks",finding:c+" risk tasks found."};
return{status:"value_blocker",actualValue:"0 tasks",finding:"No risk tasks found."};
})()","ai_justification":"Risk task volume indicates the operational workload that AI Agents can automate through assignment, follow-up, and escalation. Adequate task volume maximizes the productivity gains from Now Assist task management and automated risk workflows.","remediation_guidance":"Ensure risk tasks are being generated from assessments.","is_manual":"0","is_clone_sensitive":"0"},{"module":"TPRM","check_name":"TPRM Plugin Installed","order":null,"check_script":"(function(){
var sa=new GlideRecord("sys_store_app");
sa.addQuery("scope","sn_vdr_risk_asmt");
sa.setLimit(1);sa.query();
if(sa.next())return{status:"ready",actualValue:"v"+sa.getValue("version"),finding:"TPRM is installed."};
return{status:"value_blocker",actualValue:"Not installed",finding:"Third-party Risk Management (sn_vdr_risk_asmt) is not installed. All TPRM AI checks cannot be evaluated."};
})()","ai_justification":"The TPRM base plugin (sn_vdr_risk_asmt) is the foundational requirement for all third-party risk management capabilities including Now Assist assessment summarization and AI-powered vendor risk scoring. Without this plugin no TPRM AI features can be activated.","remediation_guidance":"Install Third-party Risk Management from the ServiceNow Store.","is_manual":"0","is_clone_sensitive":"0"},{"module":"TPRM","check_name":"Third-party Assessment Volume","order":null,"check_script":"(function(){
var ga=new GlideAggregate("sn_vdr_risk_asmt_assessment");
ga.addAggregate("COUNT");ga.query();
var c=ga.next()?parseInt(ga.getAggregate("COUNT")):0;
if(c>=100)return{status:"ready",actualValue:c+" assessments",finding:c+" assessments found."};
if(c>0)return{status:"needs_attention",actualValue:c+" assessments",finding:c+" assessments found."};
return{status:"value_blocker",actualValue:"0 assessments",finding:"No assessments found."};
})()","ai_justification":"Third-party assessment volume determines the scale of benefit from Now Assist assessment summarization and AI-assisted scoring. Higher assessment volumes mean greater time savings for risk analysts who benefit most from AI-generated summaries and recommended risk ratings.","remediation_guidance":"Initiate third-party risk assessments to build the data foundation for AI issue recommendations.","is_manual":"0","is_clone_sensitive":"0"},{"module":"TPRM","check_name":"Issue Generation Rules Configured","order":null,"check_script":"(function(){
var ga=new GlideAggregate("sn_vdr_risk_asmt_issue_generation_rule");
ga.addAggregate("COUNT");ga.query();
var c=ga.next()?parseInt(ga.getAggregate("COUNT")):0;
if(c>=3)return{status:"ready",actualValue:c+" rules",finding:c+" issue generation rules configured."};
if(c>0)return{status:"needs_attention",actualValue:c+" rules",finding:c+" rule(s) found."};
return{status:"value_blocker",actualValue:"0 rules",finding:"No issue generation rules configured."};
})()","ai_justification":"Issue generation rules define the conditions under which Now Assist automatically creates risk issues from assessment responses. Properly configured rules are required for AI-powered issue generation to function accurately and reduce false positives.","remediation_guidance":"Configure issue generation rules to automate risk issue creation.","is_manual":"0","is_clone_sensitive":"0"},{"module":"TPRM","check_name":"TPRM Knowledge Base Articles","order":null,"check_script":"(function(){
var ga=new GlideAggregate("kb_knowledge");
ga.addQuery("workflow_state","published");
ga.addQuery("short_description","CONTAINS","vendor");
ga.addAggregate("COUNT");ga.query();
var c=ga.next()?parseInt(ga.getAggregate("COUNT")):0;
if(c>=10)return{status:"ready",actualValue:c+" articles",finding:c+" vendor KB articles found."};
if(c>0)return{status:"needs_attention",actualValue:c+" articles",finding:c+" vendor KB articles found."};
return{status:"value_blocker",actualValue:"0 articles",finding:"No vendor KB articles found."};
})()","ai_justification":"TPRM knowledge base articles provide the domain content that Now Assist uses to generate accurate responses to vendor risk questions and assessment guidance. Without sufficient knowledge content, AI search results and self-service recommendations will be incomplete.","remediation_guidance":"Create KB articles covering vendor risk policies, assessment procedures, and compliance requirements.","is_manual":"0","is_clone_sensitive":"0"},{"module":"TPRM","check_name":"Vendor Engagement Volume","order":null,"check_script":"(function(){
var ga=new GlideAggregate("sn_vdr_risk_asmt_vendor_engagement");
ga.addAggregate("COUNT");ga.query();
var c=ga.next()?parseInt(ga.getAggregate("COUNT")):0;
if(c>=50)return{status:"ready",actualValue:c+" engagements",finding:c+" vendor engagements found."};
if(c>0)return{status:"needs_attention",actualValue:c+" engagements",finding:c+" vendor engagements found."};
return{status:"value_blocker",actualValue:"0 engagements",finding:"No vendor engagements found."};
})()","ai_justification":"Vendor engagement volume reflects active third-party relationship management activity that benefits from AI-assisted monitoring and risk signal detection. Higher engagement volumes increase the ROI of Now Assist vendor risk analysis capabilities.","remediation_guidance":"Initiate vendor engagements in TPRM to build the data foundation for AI risk assessment.","is_manual":"0","is_clone_sensitive":"0"},{"module":"TPRM","check_name":"TPRM Assignment Groups Configured","order":null,"check_script":"(function(){
var ga=new GlideAggregate("sys_user_group");
ga.addQuery("name","CONTAINS","risk");
ga.addAggregate("COUNT");ga.query();
var c=ga.next()?parseInt(ga.getAggregate("COUNT")):0;
if(c>=2)return{status:"ready",actualValue:c+" groups",finding:c+" risk assignment groups found."};
if(c>0)return{status:"needs_attention",actualValue:c+" group",finding:c+" risk group found."};
return{status:"value_blocker",actualValue:"0 groups",finding:"No risk assignment groups found."};
})()","ai_justification":"TPRM assignment groups ensure AI Agent task routing and Now Assist escalations reach the correct risk and vendor management teams. Without properly configured groups, automated assignments from AI-generated risk actions will fail or go unaddressed.","remediation_guidance":"Configure TPRM assignment groups aligned to risk tiers and vendor categories.","is_manual":"0","is_clone_sensitive":"0"},{"module":"TPRM","check_name":"Assessment Templates Configured","order":null,"check_script":"(function(){
var ga=new GlideAggregate("sn_vdr_risk_asmt_template");
ga.addAggregate("COUNT");ga.query();
var c=ga.next()?parseInt(ga.getAggregate("COUNT")):0;
if(c>=3)return{status:"ready",actualValue:c+" templates",finding:c+" assessment templates configured."};
if(c>0)return{status:"needs_attention",actualValue:c+" templates",finding:c+" template(s) found."};
return{status:"value_blocker",actualValue:"0 templates",finding:"No assessment templates configured."};
})()","ai_justification":"Assessment templates define the structure for vendor evaluations that Now Assist uses to generate AI-assisted scoring and summaries. Well-configured templates improve the accuracy and consistency of AI-generated assessment outputs.","remediation_guidance":"Configure assessment templates in TPRM to standardize vendor evaluations.","is_manual":"0","is_clone_sensitive":"0"}];
    },
    type: 'AROPCheckSeeder_TPRM'
};
